def solve(n: Long): String = {
  // Function to convert a number to a given base (hex or base36)
  def convertToBase(number: Long, base: Int): String = {
    if (number == 0) "0"
    else {
      val digits = List('0' to '9', 'A' to 'Z').flatMap(_.toSet).toList
      val result = scala.collection.mutable.ListBuffer.empty[Char]
      var num = number
      while (num > 0) {
        val remainder = num % base
        result += digits(remainder).toChar
        num /= base
      }
      result.reverse.mkString
    }
  }

  // Calculate n^2 and n^3
  val n2 = n * n
  val n3 = n * n * n

  // Convert to hexadecimal and base36
  val hex = convertToBase(n2, 16)
  val base36 = convertToBase(n3, 36)

  // Concatenate and return
  hex + base36
}
